    auto http = Board::GetInstance().GetNetwork()->CreateHttp(0);

    // Set user agent header
    http->SetHeader("User-Agent", "ESP32-OTA-Client/1.0");

    // Set language header
    http->SetHeader("Accept-Language", LANG_CONFIG);

    // Set content type header
    http->SetHeader("Content-Type", "application/json");

    // Set device identification header
    auto& board = Board::GetInstance();
    std::string device_id = board.GetDeviceId();
    if (!device_id.empty()) {
        http->SetHeader("X-Device-ID", device_id);
    }

    // Set serial number header if available
    if (has_serial_number_) {
        http->SetHeader("X-Serial-Number", serial_number_);
    }

    return http;
}

