bool AudioCodec::InputData(std::vector<int16_t>& data) {
    if (!input_enabled_) {
        return false;
    }

    if (rx_handle_ == nullptr) {
        return false;
    }

    // Calculate how many samples we want to read
    int samples_to_read = data.size();

    // Call the pure virtual Read method to actually read from I2S
    int samples_read = Read(data.data(), samples_to_read);

    // Return true if we successfully read some samples
    return samples_read > 0;
}

