AudioDebugger::AudioDebugger() {
#if CONFIG_USE_AUDIO_DEBUGGER
    // Initialize socket file descriptor
    udp_sockfd_ = -1;

    // Create UDP socket
    udp_sockfd_ = socket(AF_INET, SOCK_DGRAM, 0);
    if (udp_sockfd_ < 0) {
        ESP_LOGE(TAG, "Failed to create UDP socket: %d", errno);
        return;
    }

    // Initialize server address structure
    memset(&udp_server_addr_, 0, sizeof(udp_server_addr_));
    udp_server_addr_.sin_family = AF_INET;

    // Parse IP address from configuration
    if (inet_aton(CONFIG_AUDIO_DEBUG_UDP_SERVER, &udp_server_addr_.sin_addr) == 0) {
        ESP_LOGE(TAG, "Invalid IP address: %s", CONFIG_AUDIO_DEBUG_UDP_SERVER);
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        return;
    }

    // Parse port from configuration
    char* endptr;
    long port = strtol(CONFIG_AUDIO_DEBUG_UDP_SERVER_PORT, &endptr, 10);
    if (*endptr != '\0' || port <= 0 || port > 65535) {
        ESP_LOGE(TAG, "Invalid port number: %s", CONFIG_AUDIO_DEBUG_UDP_SERVER_PORT);
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        return;
    }
    udp_server_addr_.sin_port = htons(static_cast<uint16_t>(port));

    ESP_LOGI(TAG, "UDP socket initialized successfully to %s:%s", 
             CONFIG_AUDIO_DEBUG_UDP_SERVER, CONFIG_AUDIO_DEBUG_UDP_SERVER_PORT);
#endif
}

