void AfeWakeWord::AudioDetectionTask() {
    ESP_LOGI(TAG, "Audio detection task started");

    while (true) {
        // Wait for detection to be enabled
        EventBits_t bits = xEventGroupWaitBits(event_group_, 
                                               DETECTION_RUNNING_EVENT, 
                                               pdFALSE, 
                                               pdFALSE, 
                                               portMAX_DELAY);

        if (bits & DETECTION_RUNNING_EVENT) {
            // Check if we have valid AFE data
            if (afe_data_ == nullptr) {
                vTaskDelay(100 / portTICK_PERIOD_MS);
                continue;
            }

            // Perform detection
            int result = afe_iface_->detect(afe_data_);

            if (result >= 0) {
                // Wake word detected
                ESP_LOGI(TAG, "Wake word detected: %d", result);

                // Get the actual wake word name
                if (result >= 0 && result < static_cast<int>(wake_words_.size())) {
                    last_detected_wake_word_ = wake_words_[result];

                    // Stop detection temporarily
                    Stop();

                    // Store the audio data
                    const int16_t* buffer = afe_iface_->get_last_detected_buffer(afe_data_);
                    size_t buffer_size = afe_iface_->get_last_detected_size(afe_data_);

                    if (buffer && buffer_size > 0) {
                        StoreWakeWordData(buffer, buffer_size);
                    }

                    // Trigger callback if set
                    if (wake_word_detected_callback_) {
                        wake_word_detected_callback_(last_detected_wake_word_);
                    }
                }
            }

            // Small delay to prevent excessive CPU usage
            vTaskDelay(10 / portTICK_PERIOD_MS);
        }
    }
}

