void AfeWakeWord::EncodeWakeWordData() {
    // Create a static task for encoding wake word data
    if (wake_word_encode_task_ == nullptr) {
        // Allocate memory for task control block and stack
        wake_word_encode_task_buffer_ = (StaticTask_t*)heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_SPIRAM);
        wake_word_encode_task_stack_ = (StackType_t*)heap_caps_malloc(4096, MALLOC_CAP_SPIRAM);

        if (wake_word_encode_task_buffer_ == nullptr || wake_word_encode_task_stack_ == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate memory for encode task");
            return;
        }

        // Create the task with static allocation
        wake_word_encode_task_ = xTaskCreateStatic([](void* arg) {
            auto this_ = (AfeWakeWord*)arg;
            // Initialize Opus encoder with low complexity settings
            OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, nullptr);
            if (encoder == nullptr) {
                ESP_LOGE(TAG, "Failed to create Opus encoder");
                return;
            }

            opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0)); // Low complexity

            while (true) {
                // Wait for data to encode
                std::unique_lock<std::mutex> lock(this_->wake_word_mutex_);
                this_->wake_word_cv_.wait(lock, [this_]() {
                    return !this_->wake_word_pcm_.empty();
                });

                // Process all available PCM data
                while (!this_->wake_word_pcm_.empty()) {
                    auto pcm_data = this_->wake_word_pcm_.front();
                    this_->wake_word_pcm_.pop_front();
                    lock.unlock();

                    // Encode PCM data to Opus
                    std::vector<uint8_t> opus_packet(pcm_data.size() * 2); // Estimate buffer size
                    int opus_len = opus_encode(encoder, pcm_data.data(), pcm_data.size(), 
                                              opus_packet.data(), opus_packet.size());

                    if (opus_len > 0) {
                        opus_packet.resize(opus_len);

                        // Store encoded data in thread-safe buffer
                        std::lock_guard<std::mutex> guard(this_->wake_word_mutex_);
                        this_->wake_word_opus_.push_back(std::move(opus_packet));

                        // Signal completion
                        this_->wake_word_cv_.notify_one();
                    }

                    lock.lock();
                }

                // Release lock before next iteration
                lock.unlock();
            }

            opus_encoder_destroy(encoder);
        }, "wake_word_encode", 4096, this, 1, wake_word_encode_task_stack_, wake_word_encode_task_buffer_);
    }

    // Start the encoding task if not already running
    if (wake_word_encode_task_ != nullptr) {
        vTaskResume(wake_word_encode_task_);
    }
}

