bool CustomWakeWord::Initialize(AudioCodec* codec, srmodel_list_t* models_list) {
    codec_ = codec;

    // Parse the wake word model configuration from index.json
    ParseWakenetModelConfig();

    // If models_list is null, we need to initialize the models
    if (models_list == nullptr) {
        models_ = esp_srmodel_init("model");
    } else {
        models_ = models_list;
    }

    // Check if models were initialized successfully
    if (models_ == nullptr || models_->num == -1) {
        ESP_LOGE(TAG, "Failed to initialize multinet model");
        return false;
    }

    if (models_->num > 1) {
        ESP_LOGW(TAG, "More than one model found, using the first one");
    } else if (models_->num == 0) {
        ESP_LOGE(TAG, "No model found");
        return false;
    }

    // Get the model name and create the multinet interface
    char* model_name = models_->model_name[0];
    multinet_ = (esp_mn_iface_t*)esp_mn_handle_from_name(model_name);

    if (multinet_ == nullptr) {
        ESP_LOGE(TAG, "Failed to get multinet handle for model: %s", model_name);
        return false;
    }

    // Create the multinet model data with specified parameters
    multinet_model_data_ = multinet_->create(model_name, language_.c_str(), threshold_);

    if (multinet_model_data_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create multinet model data");
        return false;
    }

    // Get audio parameters from the multinet model
    int frequency = multinet_->get_samp_rate(multinet_model_data_);
    int audio_chunksize = multinet_->get_samp_chunksize(multinet_model_data_);

    ESP_LOGI(TAG, "Custom wake word model(%s), freq: %d, chunksize: %d, language: %s, threshold: %f", 
             model_name, frequency, audio_chunksize, language_.c_str(), threshold_);

    return true;
}

