std::string Board::GenerateUuid() {
    // UUID v4 щЬАшжБ 16 хнЧшКВчЪДщЪПцЬ║цХ░цНо
    uint8_t uuid[16];

    // ф╜┐чФи ESP32 чЪДчбмф╗╢щЪПцЬ║цХ░чФЯцИРхЩи
    esp_fill_random(uuid, sizeof(uuid));

    // шо╛ч╜очЙИцЬм (чЙИцЬм 4) хТМхПШф╜Уф╜Н
    uuid[6] = (uuid[6] & 0x0F) | 0x40;    // чЙИцЬм 4
    uuid[8] = (uuid[8] & 0x3F) | 0x80;    // хПШф╜У 1

    // х░ЖхнЧшКВш╜мцНвф╕║цаЗхЗЖчЪД UUID хнЧчмжф╕▓ца╝х╝П
    char uuid_str[37];
    snprintf(uuid_str, sizeof(uuid_str),
        "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
        uuid[0], uuid[1], uuid[2], uuid[3],
