std::string Board::GetSystemInfoJson() {
    // Create JSON object
    cJSON* root = cJSON_CreateObject();
    if (!root) {
        return "";
    }

    // Hardware information
    cJSON* hardware = cJSON_CreateObject();
    if (hardware) {
        // Chip model
        esp_chip_info_t chip_info;
        esp_chip_info(&chip_info);
        char chip_model[32];
        snprintf(chip_model, sizeof(chip_model), "ESP32-%s", 
                 chip_info.model == CHIP_ESP32 ? "ESP32" : 
                 chip_info.model == CHIP_ESP32S2 ? "ESP32-S2" : 
                 chip_info.model == CHIP_ESP32S3 ? "ESP32-S3" : 
                 chip_info.model == CHIP_ESP32C3 ? "ESP32-C3" : "Unknown");
        cJSON_AddStringToObject(hardware, "chip_model", chip_model);

        // Flash size
        size_t flash_size = 0;
        esp_flash_get_size(NULL, &flash_size);
        cJSON_AddNumberToObject(hardware, "flash_size_bytes", flash_size);

        // MAC address
        uint8_t mac[6];
        esp_efuse_mac_get_default(mac);
        char mac_str[18];
        snprintf(mac_str, sizeof(mac_str), "%02X:%02X:%02X:%02X:%02X:%02X",
                 mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
        cJSON_AddStringToObject(hardware, "mac_address", mac_str);

        cJSON_AddItemToObject(root, "hardware", hardware);
    }

    // Application metadata
    cJSON* app_metadata = cJSON_CreateObject();
    if (app_metadata) {
        // Application name (from BOARD_NAME macro)
        cJSON_AddStringToObject(app_metadata, "name", BOARD_NAME);

        // Version (from esp_app_desc)
        const esp_app_desc_t* app_desc = esp_ota_get_app_description();
        if (app_desc) {
            cJSON_AddStringToObject(app_metadata, "version", app_desc->version);
            cJSON_AddStringToObject(app_metadata, "compile_time", app_desc->date);
        }

        cJSON_AddItemToObject(root, "application", app_metadata);
    }

    // Partition information
    cJSON* partitions = cJSON_CreateObject();
    if (partitions) {
        const esp_partition_t* running_partition = esp_ota_get_running_partition();
        if (running_partition) {
            cJSON_AddStringToObject(partitions, "running_partition", running_partition->label);
            cJSON_AddNumberToObject(partitions, "partition_size", running_partition->size);
        }

        // Add more partition info if needed
        cJSON_AddItemToObject(root, "partitions", partitions);
    }

    // Runtime information
    cJSON* runtime = cJSON_CreateObject();
    if (runtime) {
        // Minimum free heap size
        size_t min_free_heap = esp_get_minimum_free_heap_size();
        cJSON_AddNumberToObject(runtime, "min_free_heap_bytes", min_free_heap);

        cJSON_AddItemToObject(root, "runtime", runtime);
    }

    // Unique identifiers
    cJSON_AddStringToObject(root, "uuid", uuid_.c_str());

    // Convert to string
    char* json_str = cJSON_PrintUnformatted(root);
    std::string result(json_str);

    // Clean up
    cJSON_Delete(root);
    free(json_str);

    return result;
}

