        case PowerSaveLevel::BALANCED:
            // Set Wi-Fi to balanced power saving
            wifi_manager.SetPowerSave(WifiPowerSave::BALANCED);
            break;
        case PowerSaveLevel::PERFORMANCE:
            // Set Wi-Fi to no power saving (maximum performance)
            wifi_manager.SetPowerSave(WifiPowerSave::NONE);
            break;
        default:
            // Default to balanced if unknown level
            wifi_manager.SetPowerSave(WifiPowerSave::BALANCED);
            break;
    }
}

