    // Add audio speaker volume
    int volume = audio.GetVolume();
    json += "\"volume\":" + std::to_string(volume) + ",";

    // Add screen brightness and theme
    int brightness = display.GetBrightness();
    json += "\"brightness\":" + std::to_string(brightness) + ",";

    // Add theme (assuming it's stored in settings)
    auto& settings = Settings::GetInstance();
    std::string theme = settings.GetTheme();
    json += "\"theme\":\"" + theme + "\",";

    // Add battery level and charging state
    auto& power = PowerManager::GetInstance();
    int battery_level = power.GetBatteryLevel();
    bool is_charging = power.IsCharging();
    json += "\"battery\":" + std::to_string(battery_level) + ",";
    json += "\"charging\":" + (is_charging ? "true" : "false") + ",";

    // Add WiFi network details
