bool MqttProtocol::StartMqttClient(bool report_error) {
    // Check if we're already connected
    if (mqtt_ != nullptr && mqtt_->IsConnected()) {
        ESP_LOGI(TAG, "MQTT client already connected");
        return true;
    }

    // Create new MQTT client instance
    auto network = Board::GetInstance().GetNetwork();
    mqtt_ = network->CreateMqtt();

    // Configure MQTT settings
    MqttConfig config;
    config.broker_endpoint = Settings::GetInstance().GetMqttBrokerEndpoint();
    config.client_id = Settings::GetInstance().GetDeviceId();
    config.username = Settings::GetInstance().GetMqttUsername();
    config.password = Settings::GetInstance().GetMqttPassword();
    config.keep_alive_seconds = MQTT_PING_INTERVAL_SECONDS;

    // Set up MQTT event handlers
    mqtt_->OnConnected([this]() {
        ESP_LOGI(TAG, "MQTT connected");
        // Reset reconnect timer on successful connection
        if (reconnect_timer_ != nullptr) {
            esp_timer_stop(reconnect_timer_);
        }

        // Subscribe to topics after connection
        if (!publish_topic_.empty()) {
            mqtt_->Subscribe(publish_topic_);
        }
    });

    mqtt_->OnDisconnected([this]() {
        ESP_LOGW(TAG, "MQTT disconnected");
        // Schedule reconnect attempt
        if (reconnect_timer_ != nullptr) {
            esp_timer_start_once(reconnect_timer_, MQTT_RECONNECT_INTERVAL_MS * 1000);
        }
    });

    mqtt_->OnMessage([this](const std::string& topic, const std::string& payload) {
        ESP_LOGI(TAG, "MQTT message received on topic: %s", topic.c_str());

        // Parse JSON payload
        cJSON* root = cJSON_Parse(payload.c_str());
        if (root == nullptr) {
            ESP_LOGE(TAG, "Failed to parse MQTT message JSON: %s", payload.c_str());
            return;
        }

        // Handle different message types
        auto type = cJSON_GetObjectItem(root, "type");
        if (type != nullptr && cJSON_IsString(type)) {
            if (strcmp(type->valuestring, "hello") == 0) {
                ParseServerHello(root);
            } else if (strcmp(type->valuestring, "goodbye") == 0) {
                CloseAudioChannel();
            }
        }

        cJSON_Delete(root);
    });

    // Attempt to connect
    if (!mqtt_->Connect(config)) {
        ESP_LOGE(TAG, "Failed to connect to MQTT broker");
        if (report_error) {
            SetError(Lang::Strings::SERVER_ERROR);
        }
        return false;
    }

    ESP_LOGI(TAG, "MQTT client started successfully");
    return true;
}

